#include<bits/stdc++.h>
using namespace std;
int a[1005];
int n, k;
vector<int> e[1005];
int v[1005];
int dfs(int x, int step, int black) {
	if (black > k) {
		return step - 1;
	} else {
		v[x] = 1;
		int ans = step;
		for (int i = 0; i < e[x].size(); i++) {
			if (!v[e[x][i]]) {
				if(a[e[x][i]]==1) ans = max(ans, dfs(e[x][i], step + 1,black+1));
				else ans = max(ans, dfs(e[x][i], step + 1,black));
			}
		}
		v[x] = 0;
		return ans;
	}

}
int main() {
	cin >> n >> k;
	for(int i=1;i<=n;i++) cin>>a[i];
	for (int i=1;i<=n-1;i++){
		int x,y;
		cin>>x>>y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
	int ans=0;
	for(int i=1;i<=n;i++) if(dfs(i,1,a[i])>ans) ans=dfs(i,1,a[i]);
	cout<<ans;
	return 0;
}
